import (
	"fmt"
	"errors"
	"strconv"
)

func calculateFactorial(n int64) (int64, error) {
	if n < 0 {
		return 0, errors.New("factorial is not defined for negative numbers")
	} else if n == 0 || n == 1 {
		return 1, nil
	} else {
		factorial, err := calculateFactorial(n-1)
		if err != nil {
			return 0, err
		}
		return factorial * n, nil
	}
}

func main() {
	var number int64
	fmt.Print("Enter a non-negative integer: ")
	fmt.Scanln(&number)

	if _, err := calculateFactorial(number); err != nil {
		fmt.Println(err)
		return
	}

	fmt.Println("Factorial of", number, "is:", number)
}
