using System;
using System.Collections.Generic;
using System.IO;
using System.Text.Json;

public class Program
{
    public static void Main()
    {
        Console.Write("Enter the path to the JSON file: ");
        string filePath = Console.ReadLine();

        try
        {
            if (!File.Exists(filePath))
            {
                Console.WriteLine("The file does not exist.");
                return;
            }

            string json = File.ReadAllText(filePath);
            try
            {
                var data = JsonSerializer.Deserialize<MyData>(json);
                Console.Write("Enter the key to modify: ");
                string key = Console.ReadLine();
                Console.Write("Enter the new value: ");
                string newValue = Console.ReadLine();

                data = UpdateValue(data, key, newValue);

                var updatedJson = JsonSerializer.Serialize(data);
                try
                {
                    File.WriteAllText(filePath, updatedJson);
                    Console.WriteLine("The JSON file has been updated successfully.");
                }
                catch (Exception ex)
                {
                    Console.WriteLine("An error occurred while writing to the file: " + ex.Message);
                }
            }
            catch (JsonException ex)
            {
                Console.WriteLine("An error occurred while deserializing the JSON: " + ex.Message);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine("An error occurred while reading the file: " + ex.Message);
        }
    }

    public static T UpdateValue<T>(T data, string key, string newValue) where T : class
    {
        if (data is Dictionary<string, object> dict)
        {
            dict[key] = newValue;
            return dict;
        }
        else if (data is List<object> list)
        {
            for (int i = 0; i < list.Count; i++)
            {
                if (list[i] is Dictionary<string, object> dictItem)
                {
                    dictItem = UpdateValue(dictItem, key, newValue);
                    list[i] = dictItem;
                }
                else if (list[i].ToString() == key)
                {
                    list[i] = newValue;
                }
            }
            return list;
        }
        else
        {
            throw new ArgumentException("The object is not a dictionary or list.");
        }
    }
}

public class MyData
{
    public Dictionary<string, object> Data { get; set; }
}
