    var respChan chan Response
    respChan = make(chan Response)

    for _, url := range urls {
        wg.Add(1)
        go func(url string) {
            defer wg.Done()
            resp := fetchUrl(url)
            mu.Lock()
            respChan <- resp
            mu.Unlock()
        }(url)
    }

    go func() {
        wg.Wait()
        close(respChan)
    }()

    var totalSuccess int
    var totalError string
    for resp := range respChan {
        mu.Lock()
        if resp.Success {
            totalSuccess++
        } else if resp.Error != "" {
            totalError += resp.Error + " "
        }
        mu.Unlock()
    }

    mu.Lock()
    if totalError != "" {
        log.Println(totalError)
    } else {
        log.Println(totalSuccess, "successful responses")
    }
    mu.Unlock()
}

func fetchUrl(url string) Response {
    resp, err := http.Get(url)
    if err != nil {
        return Response{Url: url, Success: false, Error: err.Error()}
    }
    defer resp.Body.Close()

    body, err := ioutil.ReadAll(resp.Body)
    if err != nil {
        return Response{Url: url, Success: false, Error: err.Error()}
    }

    if resp.StatusCode >= 200 && resp.StatusCode < 300 {
        return Response{Url: url, Success: true, Error: ""}
    } else {
        return Response{Url: url, Success: false, Error: fmt.Sprintf("Failed with status code %d", resp.StatusCode)}
    }
}
