class UserInputComponent {
  constructor() {
    this.state = {
      userInput: '',
      inputs: []
    };

    this.state.inputs = this.processInput(this.state.inputs);
  }

  processInput = (inputs) => {
    const mapResult = inputs.map(input => input.toUpperCase());
    return mapResult;
  };

  changeInput = (event) => {
    this.setState({ userInput: event.target.value });
    this.state.inputs = this.processInput(this.state.inputs);
  };

  handleSubmit = () => {
    this.state.inputs.push(this.state.userInput);
    this.setState({ userInput: '' });
    this.state.inputs = this.processInput(this.state.inputs);
  };

  render() {
    return (
      <div>
        <input type="text" value={this.state.userInput} onChange={this.changeInput} />
        <button onClick={this.handleSubmit}>Submit</button>
        <ul>
          {this.state.inputs.map((input, index) => (
            <li key={index}>{input}</li>
          ))}
        </ul>
      </div>
    );
  }
}

const App = () => {
  return (
    <UserInputComponent />
  );
};

